INSERT INTO t_document (title, content, file_name, file_type, file_size, chunk_count, uploader_id) VALUES
(
    '公司考勤管理制度',
    '公司考勤管理制度\n\n第一章 总则\n\n第一条 为规范公司考勤管理，严肃工作纪律，保障正常的工作秩序，根据国家相关法律法规，结合公司实际情况，制定本制度。\n\n第二条 本制度适用于公司全体在职员工，包括试用期员工。\n\n第三条 考勤管理应遵循公平、公正、公开的原则。\n\n第二章 工作时间\n\n第四条 公司实行标准工时制，每周工作五天，周一至周五为工作日。\n\n第五条 标准工作时间为上午9:00至12:00，下午13:30至18:00，共计7.5小时。\n\n第六条 公司可根据业务需要实行弹性工作制，弹性工作时间为上午8:00-10:00到岗，对应下班时间为17:00-19:00。\n\n第三章 打卡规定\n\n第七条 员工上下班须通过公司门禁系统刷卡或使用企业微信考勤打卡。\n\n第八条 忘记打卡的员工须在3个工作日内在OA系统提交补卡申请，经部门负责人审批后生效，每月补卡不得超过3次。\n\n第四章 请假管理\n\n第九条 员工请假须提前在OA系统提交请假申请，经审批后方可休假。\n\n第十条 请假类型包括：年假、事假、病假、婚假、产假、陪产假、丧假等。\n\n第十一条 年假天数：工作满1年不满10年的，年休假5天；满10年不满20年的，年休假10天；满20年的，年休假15天。\n\n第十二条 病假须提供二级以上医院出具的病假证明。\n\n第五章 加班管理\n\n第十三条 公司不鼓励加班，确因工作需要加班的，须提前在OA系统提交加班申请。\n\n第十四条 加班时间以小时为单位计算，不足1小时的不计入加班。\n\n第十五条 工作日加班按1.5倍工资计算，休息日加班按2倍工资计算，法定节假日加班按3倍工资计算。\n\n第十六条 加班后可选择调休或领取加班费，调休须在加班发生后30日内使用完毕。\n\n第六章 迟到与旷工\n\n第十七条 迟到30分钟以内每次扣款20元，迟到30分钟至1小时每次扣款50元，迟到1小时以上按旷工半天处理。\n\n第十八条 旷工半天扣发当日工资，旷工一天扣发当日工资并警告处分，连续旷工3天或月累计旷工5天按自动离职处理。',
    '考勤管理制度.pdf', 'pdf', 204800, 5, 1
),
(
    '新员工入职指南',
    '新员工入职指南\n\n欢迎加入公司！为了让您尽快融入团队并顺利开展工作，请仔细阅读以下入职指南。\n\n一、入职准备材料\n\n请于报到当天携带以下材料：\n1. 身份证原件及复印件2份\n2. 学历学位证书原件及复印件\n3. 离职证明（应届毕业生无需提供）\n4. 一寸免冠照片3张\n5. 本人银行卡信息（用于工资发放）\n6. 体检报告（近3个月内）\n\n二、入职流程\n\n1. 到人力资源部报到，提交入职材料\n2. 签订劳动合同（一式两份）\n3. 领取工牌、办公用品、电脑设备\n4. 由IT部门开通企业邮箱、OA系统、企业微信等账号\n5. 用人部门负责人或导师带领熟悉工位和办公环境\n6. 参加新员工入职培训（入职后一周内安排）\n\n三、试用期管理\n\n1. 试用期为3个月，表现优秀者可申请提前转正\n2. 试用期工资为转正工资的80%\n3. 试用期内享受五险一金\n4. 试用期满前2周，需提交转正述职报告\n5. 试用期不合格者，公司可依法解除劳动合同\n\n四、薪酬福利\n\n1. 薪资发放日期为每月15日，发放上月工资\n2. 薪酬结构：基本工资 + 绩效工资 + 各类补贴\n3. 五险一金：养老保险、医疗保险、失业保险、工伤保险、生育保险及住房公积金\n4. 餐饮补贴：每月500元打入员工饭卡\n5. 交通补贴：每月200元随工资发放\n6. 通讯补贴：按岗位级别每月100-300元\n\n五、办公指南\n\n1. 企业邮箱格式：姓名全拼@company.com\n2. 内部通讯工具：企业微信\n3. 文件共享平台：公司内网NAS系统\n4. 会议室预定：通过OA系统预约\n5. IT支持热线：8001（内线）\n\n六、行为规范\n\n1. 遵守公司各项规章制度\n2. 保持办公区域整洁\n3. 工作时间内禁止玩游戏、看视频等与工作无关的行为\n4. 保护公司信息安全，不得泄露客户资料和商业机密\n5. 同事之间互相尊重，营造良好的工作氛围',
    '入职指南.docx', 'docx', 153600, 4, 1
),
(
    'IT安全使用规范',
    'IT安全使用规范\n\n为保障公司信息系统的安全稳定运行，保护公司信息资产，制定本规范。\n\n一、账号与密码管理\n\n1. 员工应妥善保管个人系统账号和密码，不得借予他人使用\n2. 密码长度不少于8位，须包含字母、数字和特殊字符\n3. 每90天须更换一次密码，新旧密码不得相同\n4. 禁止使用生日、电话号码等易被猜测的密码\n5. 离开工位时须锁定电脑屏幕（Windows快捷键：Win+L）\n\n二、网络使用规范\n\n1. 公司网络仅用于工作目的，禁止访问与工作无关的网站\n2. 禁止使用BT、迅雷等P2P下载工具\n3. 禁止私自搭建WiFi热点或无线路由器\n4. 办公网络已部署上网行为管理，所有网络活动均被记录\n5. 远程办公须通过公司VPN接入内网\n\n三、数据安全管理\n\n1. 重要工作文件须定期备份至公司指定服务器或NAS\n2. 核心业务数据须设置访问权限，遵循最小权限原则\n3. 禁止将公司内部文件发送至个人邮箱或网盘\n4. U盘等移动存储设备使用前须进行病毒扫描\n5. 离职时须归还所有存储设备，并删除个人设备上的公司数据\n\n四、邮件安全\n\n1. 禁止使用个人邮箱发送公司内部文件或客户资料\n2. 对来源不明的邮件附件不要轻易打开\n3. 警惕钓鱼邮件，发现可疑邮件应报告IT部门\n4. 发送涉及敏感信息的邮件须加密\n\n五、软件使用规范\n\n1. 仅允许安装和使用公司授权的正版软件\n2. 禁止安装游戏、聊天工具等与工作无关的软件\n3. 需要安装额外办公软件的，须向IT部门申请\n4. 不得私自修改、删除系统配置文件\n\n六、安全事件处理\n\n1. 发现病毒、木马等安全威胁应立即断开网络并通知IT部门\n2. 如发生数据泄露事件，须在1小时内上报部门负责人和IT安全团队\n3. IT部门定期进行安全审计和漏洞扫描\n4. 每季度组织一次全员信息安全培训',
    'IT安全规范.txt', 'txt', 51200, 3, 2
),
(
    '项目开发流程规范',
    '项目开发流程规范 V2.0\n\n本规范适用于公司所有软件项目的开发过程管理，覆盖从需求到上线的全流程。\n\n一、需求阶段\n\n1. 产品经理负责编写PRD（产品需求文档），包含需求背景、功能描述、验收标准\n2. PRD完成后由产品经理组织需求评审会，参会人员包括开发、测试、设计代表\n3. 评审通过后，需求录入项目管理工具（TAPD），确定优先级和迭代计划\n4. 需求变更须走变更流程，评估影响范围后经项目经理审批\n\n二、设计阶段\n\n1. UI/UX设计师根据PRD输出高保真设计稿\n2. 技术负责人编写技术方案文档，含架构设计、数据库设计、接口设计\n3. 技术方案须经过技术评审会议，由架构师和资深开发人员参与\n4. 评审通过后方可进入开发阶段\n\n三、开发阶段\n\n1. 所有代码须托管在GitLab，使用Git Flow分支管理策略\n2. 分支命名规范：feature/功能名、bugfix/问题描述、hotfix/紧急修复\n3. 代码须符合公司编码规范（参考《Java开发手册》《Python编码规范》）\n4. 每个功能模块须编写单元测试，覆盖率不低于70%\n5. 每日提交代码至少一次，提交信息格式：[类型] 简要描述\n6. 代码须经过Code Review方可合并至develop分支\n\n四、测试阶段\n\n1. 开发人员完成自测后提交测试申请\n2. QA工程师进行功能测试、集成测试、回归测试\n3. 发现的Bug录入缺陷管理系统并跟踪修复\n4. 所有P0/P1级Bug修复后方可上线\n5. 性能测试和压力测试由专门的性能测试团队负责\n\n五、上线阶段\n\n1. 上线前须提交上线申请，经项目经理和产品经理审批\n2. 上线时间窗口：每周二、周四的20:00至次日02:00\n3. 上线操作由运维人员和开发人员共同执行\n4. 上线后须进行线上验证，确认核心功能正常\n5. 安排值班人员监控系统运行状态，处理突发问题\n\n六、运维与回顾\n\n1. 上线后48小时内为监控期，开发人员须保持通讯畅通\n2. 项目上线后1周内召开项目回顾会议，总结经验和改进点\n3. 所有项目文档归档至公司知识库',
    '开发流程规范.pdf', 'pdf', 307200, 5, 2
),
(
    '员工福利政策说明',
    '员工福利政策说明 2026年度\n\n一、五险一金\n\n公司依法为全体员工缴纳五险一金：\n1. 养老保险：单位缴纳16%，个人缴纳8%\n2. 医疗保险：单位缴纳10%，个人缴纳2%\n3. 失业保险：单位缴纳0.5%，个人缴纳0.5%\n4. 工伤保险：单位缴纳0.2%\n5. 生育保险：单位缴纳0.8%\n6. 住房公积金：单位和个人各缴纳12%\n\n二、带薪年假\n\n1. 工作满1年不满10年：每年5天年假\n2. 工作满10年不满20年：每年10天年假\n3. 工作满20年：每年15天年假\n4. 年假可分次使用，最小请假单位为半天\n5. 当年未休完的年假可顺延至次年3月底\n\n三、餐饮与交通\n\n1. 餐饮补贴：每月500元打入员工饭卡，可在公司食堂和合作餐厅使用\n2. 公司食堂提供早、中、晚三餐，周末及节假日不开放\n3. 交通补贴：每月200元随工资发放\n\n四、健康与体检\n\n1. 每年组织一次免费健康体检，体检项目包括基础项目和个性化项目\n2. 公司为员工购买补充商业医疗保险\n3. 设立心理咨询服务热线，提供免费心理咨询\n\n五、团建与活动\n\n1. 每季度一次部门团建活动，经费标准300元/人/季度\n2. 每年一次全体年会\n3. 员工生日当月发放生日礼品和生日蛋糕\n4. 传统节日发放节日福利\n\n六、学习与发展\n\n1. 公司每年为每位员工提供2000元的培训经费\n2. 鼓励员工参加行业技术大会，可申请参会费用报销\n3. 内部技术分享会每月一次，分享者可获得额外积分奖励\n4. 优秀员工可申请攻读在职研究生，公司提供学费支持\n\n七、其他福利\n\n1. 入职满1年的员工可申请公司无息借款，额度不超过3个月工资\n2. 结婚礼金：1000元\n3. 生育礼金：2000元\n4. 丧葬慰问金：500元',
    '福利政策.docx', 'docx', 102400, 4, 1
);
